1	export type Cell = [number, number];
2	
3	const isNeighbor = (cell: Cell, other: Cell): boolean => {
4	  const dx = Math.abs(cell[0] - other[0]);
5	  const dy = Math.abs(cell[1] - other[1]);
6	  const isSameCell = dx === 0 && dy === 0;
7	  return !isSameCell && dx <= 1 && dy <= 1;
8	};
9	
10	const countLivingNeighbors = (cell: Cell, livingCells: Cell[]): number =>
11	  livingCells.filter((other) => isNeighbor(cell, other)).length;
12	
13	const survivesNextGeneration = (cell: Cell, livingCells: Cell[]): boolean => {
14	  const neighbors = countLivingNeighbors(cell, livingCells);
15	  return neighbors === 2 || neighbors === 3;
16	};
17	
18	export const nextGeneration = (livingCells: Cell[]): Cell[] =>
19	  livingCells.filter((cell) => survivesNextGeneration(cell, livingCells));
